select key, empresa_id, ativo, value from public.app_config where key in ('finance.wallet_account_enabled','finance.wallet_ledger_enabled','finance.wallet_balance_read_enabled','finance.wallet_movements_enabled','finance.wallet_manual_adjustments_enabled','finance.manual_credit_enabled','finance.payment_v2_write_enabled','finance.payment_v2_reversal_enabled') order by key, empresa_id nulls first;
